#include <algorithm>
#include <cmath>

double triangle_ref_area_2d(const RefMesh& ref_mesh, const std::vector<Vec2>& X, const Tri& tri) {
    const Vec2& X0 = X[tri.v[0]];
    const Vec2& X1 = X[tri.v[1]];
    const Vec2& X2 = X[tri.v[2]];

    Mat22 Dm_local;
    Dm_local.col(0) = X1 - X0;
    Dm_local.col(1) = X2 - X0;
    return 0.5 * std::abs(Dm_local.determinant());
}


VertexAdjacency build_vertex_adjacency(const RefMesh& ref_mesh) {
    VertexAdjacency adj;
    adj.incident_triangle_indices.resize(ref_mesh.num_positions);

    for (int t = 0; t < static_cast<int>(ref_mesh.tris.size()); ++t) {
        const Tri& tri = ref_mesh.tris[t];
        for (int a : tri.v) adj.incident_triangle_indices[a].push_back(t);
    }

    return adj;
}

double compute_incremental_potential_no_barrier(const RefMesh& ref_mesh, const std::vector<Pin>& pins,
                                                const SimParams& params, const std::vector<Vec3>& x, const std::vector<Vec3>& xhat) {
    double E = 0.0, PE = 0.0, dt2 = params.dt * params.dt;

    for (int i = 0; i < static_cast<int>(x.size()); ++i) {
        Vec3 dx = x[i] - xhat[i];
        E += 0.5 * ref_mesh.mass[i] * dx.squaredNorm();
    }

    for (int i = 0; i < static_cast<int>(x.size()); ++i)
        PE += -ref_mesh.mass[i] * params.gravity.dot(x[i]);

    for (const Pin& pin : pins) {
        Vec3 dx = x[pin.vertex_index] - pin.target_position;
        PE += 0.5 * params.kpin * dx.squaredNorm();
    }

    for (size_t t = 0; t < ref_mesh.tris.size(); ++t)
        PE += corotated_energy(ref_mesh.area[t], ref_mesh.Dm_inverse[t], make_def_triangle(x, ref_mesh.tris[t]), params.mu, params.lambda);

    return E + dt2 * PE;
}

std::pair<Vec3, Mat33> compute_local_gradient_and_hessian_no_barrier(int vi, const RefMesh& ref_mesh, const VertexAdjacency& adj, const std::vector<Pin>& pins, const SimParams& params, const std::vector<Vec3>& x, const std::vector<Vec3>& xhat){
    double dt2 = params.dt * params.dt;
    Vec3  g = Vec3::Zero();
    Mat33 H = Mat33::Zero();

    g += ref_mesh.mass[vi] * (x[vi] - xhat[vi]);
    g += dt2 * (-ref_mesh.mass[vi] * params.gravity);
    H += ref_mesh.mass[vi] * Mat33::Identity();

    for (const Pin& pin : pins) {
        if (pin.vertex_index == vi) {
            g += dt2 * params.kpin * (x[vi] - pin.target_position);
            H += dt2 * params.kpin * Mat33::Identity();
        }
    }

    for (int ti : adj.incident_triangle_indices[vi]) {
        const Tri& tri = ref_mesh.tris[ti];
        int a = -1;
        for (int j = 0; j < 3; ++j) if (tri.v[j] == vi) { a = j; break; }

        const TriangleDef def = make_def_triangle(x, tri);
        Mat32 Ds_mat;
        Ds_mat.col(0) = def.x[1] - def.x[0];
        Ds_mat.col(1) = def.x[2] - def.x[0];
        const Mat22& Dm_inv = ref_mesh.Dm_inverse[ti];
        const Mat32  F      = Ds_mat * Dm_inv;
        const double A      = ref_mesh.area[ti];

        const CorotatedCache32 cache = buildCorotatedCache(F);
        const ShapeGrads gradN = shape_function_gradients(Dm_inv);
        const Mat32 P = PCorotated32(cache, F, params.mu, params.lambda);
        Mat66 dPdF; dPdFCorotated32(cache, params.mu, params.lambda, dPdF);
        g += dt2 * corotated_node_gradient(P, A, gradN, a);
        H += dt2 * corotated_node_hessian(dPdF, A, gradN, a).template block<3, 3>(0, 3 * a);
    }

    return {g, H};
}

Vec3 compute_local_gradient_no_barrier(int vi, const RefMesh& ref_mesh, const VertexAdjacency& adj, const std::vector<Pin>& pins, const SimParams& params, const std::vector<Vec3>& x, const std::vector<Vec3>& xhat){
    double dt2 = params.dt * params.dt;
    Vec3 g = Vec3::Zero();

    g += ref_mesh.mass[vi] * (x[vi] - xhat[vi]);
    g += dt2 * (-ref_mesh.mass[vi] * params.gravity);

    for (const Pin& pin : pins) {
        if (pin.vertex_index == vi)
            g += dt2 * params.kpin * (x[vi] - pin.target_position);
    }

    for (int ti : adj.incident_triangle_indices[vi]) {
        const Tri& tri = ref_mesh.tris[ti];
        int a = -1;
        for (int j = 0; j < 3; ++j) if (tri.v[j] == vi) { a = j; break; }

        const TriangleDef def = make_def_triangle(x, tri);
        Mat32 Ds_mat;
        Ds_mat.col(0) = def.x[1] - def.x[0];
        Ds_mat.col(1) = def.x[2] - def.x[0];
        const Mat22& Dm_inv = ref_mesh.Dm_inverse[ti];
        const Mat32  F      = Ds_mat * Dm_inv;
        const double A      = ref_mesh.area[ti];

        const CorotatedCache32 cache = buildCorotatedCache(F);
        const ShapeGrads gradN = shape_function_gradients(Dm_inv);
        const Mat32 P = PCorotated32(cache, F, params.mu, params.lambda);
        g += dt2 * corotated_node_gradient(P, A, gradN, a);
    }

    return g;
}

double compute_global_residual(const RefMesh& ref_mesh, const VertexAdjacency& adj, const std::vector<Pin>& pins, const SimParams& params, const std::vector<Vec3>& x, const std::vector<Vec3>& xhat){
    double r_inf = 0.0;
    for (int i = 0; i < static_cast<int>(x.size()); ++i) {
        Vec3 g = compute_local_gradient_no_barrier(i, ref_mesh, adj, pins, params, x, xhat);
        r_inf = std::max(r_inf, g.cwiseAbs().maxCoeff());
    }
    return r_inf;
}
