#include <unordered_map>

TriangleRest make_rest_triangle(const std::vector<Vec2>& X, const Tri& tri) {
    TriangleRest rest;
    rest.X[0] = X[tri.v[0]];
    rest.X[1] = X[tri.v[1]];
    rest.X[2] = X[tri.v[2]];
    return rest;
}

TriangleDef make_def_triangle(const std::vector<Vec3>& x, const Tri& tri) {
    TriangleDef def;
    def.x[0] = x[tri.v[0]];
    def.x[1] = x[tri.v[1]];
    def.x[2] = x[tri.v[2]];
    return def;
}

void build_xhat(std::vector<Vec3>& xhat, const std::vector<Vec3>& x, const std::vector<Vec3>& v, double dt) {
    int n = static_cast<int>(x.size());
    xhat.resize(n);
    for (int i = 0; i < n; ++i) xhat[i] = x[i] + dt * v[i];
}

void update_velocity(std::vector<Vec3>& v, const std::vector<Vec3>& xnew, const std::vector<Vec3>& xold, double dt) {
    int n = static_cast<int>(xnew.size());
    v.resize(n);
    for (int i = 0; i < n; ++i) v[i] = (xnew[i] - xold[i]) / dt;
}

void clear_model(RefMesh& ref_mesh, DeformedState& state, std::vector<Vec2>& X, std::vector<Pin>& pins) {
    X.clear();
    ref_mesh.tris.clear();
    state.deformed_positions.clear();
    state.velocities.clear();
    pins.clear();
}

int build_single_triangle(RefMesh& ref_mesh, DeformedState& state, std::vector<Vec2>& X,
                          const Vec2& X0, const Vec2& X1, const Vec2& X2,
                          const Vec3& x0, const Vec3& x1, const Vec3& x2) {
    int base = static_cast<int>(state.deformed_positions.size());

    X.push_back(X0);
    X.push_back(X1);
    X.push_back(X2);

    state.deformed_positions.push_back(x0);
    state.deformed_positions.push_back(x1);
    state.deformed_positions.push_back(x2);

    ref_mesh.tris.push_back(Tri{{base + 0, base + 1, base + 2}});
    return base;
}

void append_pin(std::vector<Pin>& pins, int vertex_index, const std::vector<Vec3>& x) {
    pins.push_back(Pin{vertex_index, x[vertex_index]});
}

// Total number of vertices is: (nx + 1) * (ny + 1) and total number of triangles is: 2 * nx * ny
int build_square_mesh(RefMesh& ref_mesh, DeformedState& state, std::vector<Vec2>& X, int nx, int ny, double width, double height, const Vec3& origin) {
    int base = static_cast<int>(state.deformed_positions.size());

    for (int j = 0; j <= ny; ++j) {
        for (int i = 0; i <= nx; ++i) {

            // Normalize grid coordinates from 0 to 1
            double u = static_cast<double>(i) / nx;
            double v = static_cast<double>(j) / ny;

            // Scale to actual size
            double x_ref = u * width;
            double y_ref = v * height;

            // Store reference (2D) and deformed (3D) positions
            X.push_back(Vec2(x_ref, y_ref));
            state.deformed_positions.push_back(origin + Vec3(x_ref, y_ref, 0.0));
        }
    }

    // convert (col, row) → vertex index
    auto vertex_index = [base, nx](int i, int j) {
        return base + j * (nx + 1) + i;
    };

    // Create triangles
    for (int j = 0; j < ny; ++j) {
        for (int i = 0; i < nx; ++i) {
            int v00 = vertex_index(i, j);
            int v10 = vertex_index(i + 1, j);
            int v01 = vertex_index(i, j + 1);
            int v11 = vertex_index(i + 1, j + 1);

            // Split square into two triangles
            ref_mesh.tris.push_back(Tri{{v00, v10, v11}});
            ref_mesh.tris.push_back(Tri{{v00, v11, v01}});
        }
    }

    ref_mesh.initialize(X);

    return base;
}

std::unordered_map<int, std::vector<int>> build_incident_triangle_map(const std::vector<int>& indices) {
    std::unordered_map<int, std::vector<int>> result;
    for (int i = 0; i < static_cast<int>(indices.size()); ++i)
        result[indices[i]].push_back(i);
    return result;
}
// ===== END make_shape.cpp =====

// ===== BEGIN solver.cpp =====

void update_one_vertex(int vi, const RefMesh& ref_mesh, const VertexAdjacency& adj,
                       const std::vector<Pin>& pins, const SimParams& params, const std::vector<Vec3>& xhat, std::vector<Vec3>& x){
    auto [g, H] = compute_local_gradient_and_hessian_no_barrier(vi, ref_mesh, adj, pins, params, x, xhat);
    Vec3 dx = matrix3d_inverse(H) * g;
    x[vi] -= params.step_weight * dx;
}

SolverResult global_gauss_seidel_solver(const RefMesh& ref_mesh, const VertexAdjacency& adj,
                                        const std::vector<Pin>& pins, const SimParams& params, std::vector<Vec3>& xnew,
                                        const std::vector<Vec3>& xhat, std::vector<double>* residual_history){
    if (residual_history) residual_history->clear();

    auto eval_residual = [&]() { return compute_global_residual(ref_mesh, adj, pins, params, xnew, xhat); };

    SolverResult result;
    result.initial_residual = eval_residual();
    result.final_residual = result.initial_residual;
    result.iterations = 0;

    if (residual_history) residual_history->push_back(result.initial_residual);
    if (result.initial_residual < params.tol_abs) return result;

    for (int iter = 1; iter <= params.max_global_iters; ++iter) {
        for (int vi = 0; vi < static_cast<int>(xnew.size()); ++vi)
            update_one_vertex(vi, ref_mesh, adj, pins, params, xhat, xnew);

        result.final_residual = eval_residual();
        result.iterations = iter;

        if (residual_history) residual_history->push_back(result.final_residual);
        if (result.final_residual < params.tol_abs) return result;
    }

    return result;
}
