#include <fstream>
#include <iomanip>
#include <iostream>
#include <sstream>

void export_obj(const std::string& filename, const std::vector<Vec3>& x, const std::vector<Tri>& tris) {
    std::ofstream out(filename);
    if (!out) {
        std::cerr << "Error: cannot write " << filename << "\n";
        return;
    }

    for (const auto& p : x) out << "v " << p.x() << " " << p.y() << " " << p.z() << "\n";
    for (const auto& t : tris) out << "f " << (t.v[0] + 1) << " " << (t.v[1] + 1) << " " << (t.v[2] + 1) << "\n";
}

void export_frame(const std::string& outdir, int frame, const std::vector<Vec3>& x, const std::vector<Tri>& tris) {
    std::ostringstream ss;
    ss << outdir << "/frame_" << std::setw(4) << std::setfill('0') << frame << ".obj";
    export_obj(ss.str(), x, tris);
}
// ===== END visualization.cpp =====


// ===== BEGIN sandbox-specific barrier-integrated utilities =====

struct NodeTrianglePair {
    int node{-1};
    int tri_v[3]{-1, -1, -1};
};

struct SegmentSegmentPair {
    int v[4]{-1, -1, -1, -1};
};

struct MeshPatchInfo {
    int vertex_begin{0};
    int vertex_end{0};
    int tri_begin{0};
    int tri_end{0};
};

MeshPatchInfo build_square_patch(RefMesh& ref_mesh, DeformedState& state, std::vector<Vec2>& X,
                                 int nx, int ny, double width, double height, const Vec3& origin) {
    MeshPatchInfo patch;
    patch.vertex_begin = static_cast<int>(state.deformed_positions.size());
    patch.tri_begin = static_cast<int>(ref_mesh.tris.size());
    build_square_mesh(ref_mesh, state, X, nx, ny, width, height, origin);
    patch.vertex_end = static_cast<int>(state.deformed_positions.size());
    patch.tri_end = static_cast<int>(ref_mesh.tris.size());
    return patch;
}

std::vector<std::array<int, 2>> extract_patch_edges(const RefMesh& ref_mesh, const MeshPatchInfo& patch) {
    std::set<std::pair<int, int>> unique_edges;
    for (int ti = patch.tri_begin; ti < patch.tri_end; ++ti) {
        const Tri& tri = ref_mesh.tris[ti];
        for (int e = 0; e < 3; ++e) {
            int a = tri.v[e];
            int b = tri.v[(e + 1) % 3];
            if (a > b) std::swap(a, b);
            unique_edges.insert({a, b});
        }
    }

    std::vector<std::array<int, 2>> edges;
    edges.reserve(unique_edges.size());
    for (const auto& [a, b] : unique_edges) edges.push_back({a, b});
    return edges;
}

std::vector<NodeTrianglePair> build_inter_patch_node_triangle_pairs(const RefMesh& ref_mesh,
                                                                    const MeshPatchInfo& a,
                                                                    const MeshPatchInfo& b) {
    std::vector<NodeTrianglePair> pairs;
    for (int node = a.vertex_begin; node < a.vertex_end; ++node) {
        for (int ti = b.tri_begin; ti < b.tri_end; ++ti) {
            const Tri& tri = ref_mesh.tris[ti];
            pairs.push_back(NodeTrianglePair{node, {tri.v[0], tri.v[1], tri.v[2]}});
        }
    }
    for (int node = b.vertex_begin; node < b.vertex_end; ++node) {
        for (int ti = a.tri_begin; ti < a.tri_end; ++ti) {
            const Tri& tri = ref_mesh.tris[ti];
            pairs.push_back(NodeTrianglePair{node, {tri.v[0], tri.v[1], tri.v[2]}});
        }
    }
    return pairs;
}

std::vector<SegmentSegmentPair> build_inter_patch_segment_segment_pairs(const RefMesh& ref_mesh,
                                                                        const MeshPatchInfo& a,
                                                                        const MeshPatchInfo& b) {
    const auto edges_a = extract_patch_edges(ref_mesh, a);
    const auto edges_b = extract_patch_edges(ref_mesh, b);

    std::vector<SegmentSegmentPair> pairs;
    pairs.reserve(edges_a.size() * edges_b.size());
    for (const auto& ea : edges_a) {
        for (const auto& eb : edges_b) {
            pairs.push_back(SegmentSegmentPair{{ea[0], ea[1], eb[0], eb[1]}});
        }
    }
    return pairs;
}

double compute_incremental_potential_with_barrier(const RefMesh& ref_mesh,
                                                  const std::vector<Pin>& pins,
                                                  const SimParams& params,
                                                  const std::vector<Vec3>& x,
                                                  const std::vector<Vec3>& xhat,
                                                  const std::vector<NodeTrianglePair>& nt_pairs,
                                                  const std::vector<SegmentSegmentPair>& ss_pairs) {
    double E = compute_incremental_potential_no_barrier(ref_mesh, pins, params, x, xhat);
    if (params.d_hat <= 0.0) return E;

    const double dt2 = params.dt * params.dt;
    for (const auto& p : nt_pairs) {
        E += dt2 * node_triangle_barrier(
                x[p.node], x[p.tri_v[0]], x[p.tri_v[1]], x[p.tri_v[2]], params.d_hat);
    }
    for (const auto& p : ss_pairs) {
        E += dt2 * segment_segment_barrier(
                x[p.v[0]], x[p.v[1]], x[p.v[2]], x[p.v[3]], params.d_hat);
    }
    return E;
}

std::pair<Vec3, Mat33> compute_local_gradient_and_hessian_with_barrier(
        int vi,
        const RefMesh& ref_mesh,
        const VertexAdjacency& adj,
        const std::vector<Pin>& pins,
        const SimParams& params,
        const std::vector<Vec3>& x,
        const std::vector<Vec3>& xhat,
        const std::vector<NodeTrianglePair>& nt_pairs,
        const std::vector<SegmentSegmentPair>& ss_pairs) {
    auto [g, H] = compute_local_gradient_and_hessian_no_barrier(vi, ref_mesh, adj, pins, params, x, xhat);
    if (params.d_hat <= 0.0) return {g, H};

    const double dt2 = params.dt * params.dt;

    for (const auto& p : nt_pairs) {
        int dof = -1;
        if      (vi == p.node)      dof = 0;
        else if (vi == p.tri_v[0])  dof = 1;
        else if (vi == p.tri_v[1])  dof = 2;
        else if (vi == p.tri_v[2])  dof = 3;
        if (dof < 0) continue;
        auto [bg, bH] = node_triangle_barrier_gradient_and_hessian(
                x[p.node], x[p.tri_v[0]], x[p.tri_v[1]], x[p.tri_v[2]], params.d_hat, dof);
        g += dt2 * bg;
        H += dt2 * bH.block<3, 3>(0, 3 * dof);
    }

    for (const auto& p : ss_pairs) {
        int dof = -1;
        if      (vi == p.v[0]) dof = 0;
        else if (vi == p.v[1]) dof = 1;
        else if (vi == p.v[2]) dof = 2;
        else if (vi == p.v[3]) dof = 3;
        if (dof < 0) continue;
        auto [bg, bH] = segment_segment_barrier_gradient_and_hessian(
                x[p.v[0]], x[p.v[1]], x[p.v[2]], x[p.v[3]], params.d_hat, dof);
        g += dt2 * bg;
        H += dt2 * bH.block<3, 3>(0, 3 * dof);
    }

    return {g, H};
}

Vec3 compute_local_gradient_with_barrier(
        int vi,
        const RefMesh& ref_mesh,
        const VertexAdjacency& adj,
        const std::vector<Pin>& pins,
        const SimParams& params,
        const std::vector<Vec3>& x,
        const std::vector<Vec3>& xhat,
        const std::vector<NodeTrianglePair>& nt_pairs,
        const std::vector<SegmentSegmentPair>& ss_pairs) {
    auto [g, H] = compute_local_gradient_and_hessian_with_barrier(
            vi, ref_mesh, adj, pins, params, x, xhat, nt_pairs, ss_pairs);
    return g;
}

double compute_global_residual_with_barrier(
        const RefMesh& ref_mesh,
        const VertexAdjacency& adj,
        const std::vector<Pin>& pins,
        const SimParams& params,
        const std::vector<Vec3>& x,
        const std::vector<Vec3>& xhat,
        const std::vector<NodeTrianglePair>& nt_pairs,
        const std::vector<SegmentSegmentPair>& ss_pairs) {
    double r_inf = 0.0;
    for (int i = 0; i < static_cast<int>(x.size()); ++i) {
        const Vec3 g = compute_local_gradient_with_barrier(
                i, ref_mesh, adj, pins, params, x, xhat, nt_pairs, ss_pairs);
        r_inf = std::max(r_inf, std::abs(g.x()));
        r_inf = std::max(r_inf, std::abs(g.y()));
        r_inf = std::max(r_inf, std::abs(g.z()));
    }
    return r_inf;
}

void update_one_vertex_with_barrier(
        int vi,
        const RefMesh& ref_mesh,
        const VertexAdjacency& adj,
        const std::vector<Pin>& pins,
        const SimParams& params,
        const std::vector<Vec3>& xhat,
        const std::vector<NodeTrianglePair>& nt_pairs,
        const std::vector<SegmentSegmentPair>& ss_pairs,
        std::vector<Vec3>& x) {
    auto [g, H] = compute_local_gradient_and_hessian_with_barrier(
            vi, ref_mesh, adj, pins, params, x, xhat, nt_pairs, ss_pairs);
    const Vec3 dx = matrix3d_inverse(H) * g;
    x[vi] -= params.step_weight * dx;
}

SolverResult global_gauss_seidel_solver_with_barrier(
        const RefMesh& ref_mesh,
        const VertexAdjacency& adj,
        const std::vector<Pin>& pins,
        const SimParams& params,
        const std::vector<NodeTrianglePair>& nt_pairs,
        const std::vector<SegmentSegmentPair>& ss_pairs,
        std::vector<Vec3>& xnew,
        const std::vector<Vec3>& xhat,
        std::vector<double>* residual_history = nullptr) {
    if (residual_history) residual_history->clear();

    auto eval_residual = [&]() {
        return compute_global_residual_with_barrier(
                ref_mesh, adj, pins, params, xnew, xhat, nt_pairs, ss_pairs);
    };

    SolverResult result;
    result.initial_residual = eval_residual();
    result.final_residual = result.initial_residual;
    result.iterations = 0;

    if (residual_history) residual_history->push_back(result.initial_residual);
    if (result.initial_residual < params.tol_abs) return result;

    for (int iter = 1; iter <= params.max_global_iters; ++iter) {
        for (int vi = 0; vi < static_cast<int>(xnew.size()); ++vi) {
            update_one_vertex_with_barrier(
                    vi, ref_mesh, adj, pins, params, xhat, nt_pairs, ss_pairs, xnew);
        }

        result.final_residual = eval_residual();
        result.iterations = iter;
        if (residual_history) residual_history->push_back(result.final_residual);
        if (result.final_residual < params.tol_abs) return result;
    }

    return result;
}

// ===== END sandbox-specific barrier-integrated utilities =====

int main() {
    SimParams params;
    params.dt = 1.0 / 30.0;
    params.mu = 10.0;
    params.lambda = 10.0;
    params.density = 1.0;
    params.thickness = 0.1;
    params.kpin = 1e7;
    params.gravity = Vec3(0.0, -9.81, 0.0);
    params.max_global_iters = 80;
    params.tol_abs = 1e-6;
    params.step_weight = 1.0;
    params.d_hat = 0.75;

    RefMesh ref_mesh;
    DeformedState state;
    std::vector<Vec2> X;
    std::vector<Pin> pins;

    clear_model(ref_mesh, state, X, pins);

    const MeshPatchInfo patch_a = build_square_patch(ref_mesh, state, X, 2, 2, 1.5, 1.5, Vec3(-0.90, 0.00, 0.00));
    const MeshPatchInfo patch_b = build_square_patch(ref_mesh, state, X, 2, 2, 1.5, 1.5, Vec3(-0.25, 0.20, 0.45));

    state.velocities.assign(state.deformed_positions.size(), Vec3::Zero());

    // break symmetry so the contact terms are exercised immediately
    for (int i = patch_a.vertex_begin; i < patch_a.vertex_end; ++i) {
        const double t = static_cast<double>(i - patch_a.vertex_begin);
        state.deformed_positions[i] += Vec3(0.01 * std::sin(t), 0.00, 0.02 * std::cos(t));
    }
    for (int i = patch_b.vertex_begin; i < patch_b.vertex_end; ++i) {
        const double t = static_cast<double>(i - patch_b.vertex_begin);
        state.deformed_positions[i] += Vec3(-0.01 * std::cos(t), 0.00, -0.015 * std::sin(t));
    }

    // Pin the top corners of both patches.
    append_pin(pins, patch_a.vertex_begin + 6, state.deformed_positions);
    append_pin(pins, patch_a.vertex_begin + 8, state.deformed_positions);
    append_pin(pins, patch_b.vertex_begin + 6, state.deformed_positions);
    append_pin(pins, patch_b.vertex_begin + 8, state.deformed_positions);

    ref_mesh.initialize(X);
    ref_mesh.build_lumped_mass(params.density, params.thickness);
    const VertexAdjacency adj = build_vertex_adjacency(ref_mesh);

    const auto nt_pairs = build_inter_patch_node_triangle_pairs(ref_mesh, patch_a, patch_b);
    const auto ss_pairs = build_inter_patch_segment_segment_pairs(ref_mesh, patch_a, patch_b);

    std::cout << "Vertices:  " << state.deformed_positions.size() << "\n";
    std::cout << "Triangles: " << ref_mesh.tris.size() << "\n";
    std::cout << "NT pairs:  " << nt_pairs.size() << "\n";
    std::cout << "SS pairs:  " << ss_pairs.size() << "\n";

    std::string outdir = "frames_sandbox_barrier";
    if (fs::exists(outdir)) fs::remove_all(outdir);
    fs::create_directories(outdir);
    export_frame(outdir, 0, state.deformed_positions, ref_mesh.tris);

    const int num_frames = 60;
    using Clock = std::chrono::steady_clock;
    auto sim_start = Clock::now();
    double total_solver_ms = 0.0;

    for (int frame_index = 1; frame_index <= num_frames; ++frame_index) {
        std::vector<Vec3> xhat;
        build_xhat(xhat, state.deformed_positions, state.velocities, params.dt);

        std::vector<Vec3> xnew = state.deformed_positions;

        auto solver_start = Clock::now();
        const SolverResult result = global_gauss_seidel_solver_with_barrier(
                ref_mesh, adj, pins, params, nt_pairs, ss_pairs, xnew, xhat);
        auto solver_end = Clock::now();

        const double solver_ms = std::chrono::duration<double, std::milli>(solver_end - solver_start).count();
        total_solver_ms += solver_ms;

        const double total_energy = compute_incremental_potential_with_barrier(
                ref_mesh, pins, params, xnew, xhat, nt_pairs, ss_pairs);

        std::cout << "Frame " << std::setw(4) << frame_index
                  << " | initial_residual = " << std::scientific << result.initial_residual
                  << " | final_residual = " << std::scientific << result.final_residual
                  << " | global_iters = " << std::setw(3) << result.iterations
                  << " | energy = " << std::scientific << total_energy
                  << " | solver_time = " << std::fixed << std::setprecision(3) << solver_ms << " ms\n";

        update_velocity(state.velocities, xnew, state.deformed_positions, params.dt);
        state.deformed_positions = xnew;
        export_frame(outdir, frame_index, state.deformed_positions, ref_mesh.tris);
    }

    auto sim_end = Clock::now();
    const double total_sim_ms = std::chrono::duration<double, std::milli>(sim_end - sim_start).count();

    std::cout << "\nSimulation finished.\n";
    std::cout << "Total simulation time: " << std::fixed << std::setprecision(3) << total_sim_ms << " ms\n";
    std::cout << "Total solver time:     " << total_solver_ms << " ms\n";
    std::cout << "Average solver time:   " << (total_solver_ms / num_frames) << " ms/frame\n";
    std::cout << "Frames written to:     " << outdir << "\n";

    return 0;
}